-- Enable UUID generation
CREATE EXTENSION IF NOT EXISTS pgcrypto;

-- Create schema if missing
CREATE SCHEMA IF NOT EXISTS resume_match;

-- Create table if missing
CREATE TABLE IF NOT EXISTS resume_match.user_credit_accounts (
    user_id UUID PRIMARY KEY,
    current_balance INT NOT NULL DEFAULT 0 CHECK (current_balance >= 0),
    created_at TIMESTAMPTZ DEFAULT now(),
    updated_at TIMESTAMPTZ DEFAULT now()

);

CREATE OR REPLACE FUNCTION resume_match.set_updated_at()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = now();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_credit_accounts_updated
BEFORE UPDATE ON resume_match.user_credit_accounts
FOR EACH ROW
EXECUTE FUNCTION resume_match.set_updated_at();

-- Index on user_id for faster queries
CREATE INDEX IF NOT EXISTS idx_user_credit_accounts_user_id
ON resume_match.user_credit_accounts(user_id);

SELECT current_balance
FROM resume_match.user_credit_accounts
WHERE user_id = $1;

